export function initialize(sentinelElement, dotNetHelper) {
    const observer = new IntersectionObserver(async (entries) => {
        const entry = entries[0];
        if (entry.isIntersecting) {
            await dotNetHelper.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '0px 0px 128px 0px' });

    observer.observe(sentinelElement);

    return { observer, sentinelElement };
}

export function dispose(instance) {
    if (instance?.observer) {
        instance.observer.unobserve(instance.sentinelElement);
        instance.observer.disconnect();
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container" style="overflow-y:auto; max-height:100%;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel"
             style="display:flex; justify-content:center; padding:1rem;">
            @if (_isLoading)
            {
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    /// <summary>The collection of items to display.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>Whether additional items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when more items should be loaded.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observerInstance;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infinite-scroll.js");
        }

        // (Re-)attach the observer whenever HasMore is true and we have a module ready.
        // The sentinel element reference updates each render, so we reconnect.
        if (HasMore && _module is not null)
        {
            if (_observerInstance is not null)
            {
                await _module.InvokeVoidAsync("dispose", _observerInstance);
            }

            _observerInstance = await _module.InvokeAsync<IJSObjectReference>(
                "initialize", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            if (_observerInstance is not null)
            {
                await _module.InvokeVoidAsync("dispose", _observerInstance);
            }
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

